"""Visualize a YOLO-seg dataset generated by example 15.

Usage:
    python scripts/visualize_yolo_dataset.py <camera_dataset_root>
    python scripts/visualize_yolo_dataset.py <camera_dataset_root> --max-images 20
    python scripts/visualize_yolo_dataset.py <camera_dataset_root> --split val
    python scripts/visualize_yolo_dataset.py <camera_dataset_root> --split all

Does not require the dev container or Isaac Sim — run anywhere with
opencv-python installed.

Expected input:
    <camera_dataset_root>/
      classes.txt
      images/{train,test,val}/*.png
      labels/{train,test,val}/*.txt

Default output:
    <dataset_root>/visualizations/<split>/<image_name>.png

Supported label formats:
    YOLO bbox:
      <class_id> <cx> <cy> <w> <h>

    YOLO-seg polygon:
      <class_id> <x1> <y1> <x2> <y2> ... <xn> <yn>

All coordinates are expected to be normalized to [0, 1].

See docs/yolo_seg.md for the full workflow.
"""

from __future__ import annotations

import argparse
from collections.abc import Iterable
from dataclasses import dataclass
from pathlib import Path

import cv2
import numpy as np

SPLITS = ("train", "test", "val")


@dataclass(frozen=True)
class VisualizeConfig:
    """User-selected visualization options."""

    dataset_root: Path
    output_root: Path
    split: str
    max_images: int
    line_width: int
    alpha: float
    ignore_classes: tuple[str, ...]


def main(argv: list[str] | None = None) -> None:
    """Command-line entry point."""

    config = parse_args(argv)
    total = visualize_dataset(config)
    if total == 0:
        raise RuntimeError(
            f"No images were visualized from {config.dataset_root}. "
            f"Check split={config.split!r}, images/, labels/, and --max-images."
        )
    print(f"[visualize] wrote {total} file(s) under {config.output_root}")


def parse_args(argv: list[str] | None = None) -> VisualizeConfig:
    """Parse command-line arguments and return a validated config."""

    parser = argparse.ArgumentParser(
        description=__doc__,
        formatter_class=argparse.RawDescriptionHelpFormatter,
    )
    parser.add_argument(
        "dataset_root",
        help="YOLO dataset root containing classes.txt, images/, and labels/.",
    )
    parser.add_argument(
        "--output-dir",
        default=None,
        help=(
            "Output root. Defaults to <dataset_root>/visualizations. "
            "Split subdirectories are always created under this root."
        ),
    )
    parser.add_argument(
        "--split",
        choices=(*SPLITS, "all"),
        default="train",
        help="Dataset split to visualize. Defaults to train.",
    )
    parser.add_argument(
        "--max-images",
        type=int,
        default=1,
        help="Maximum images to visualize per split. Defaults to 1.",
    )
    parser.add_argument(
        "--line-width",
        type=int,
        default=2,
        help="Overlay line width in pixels.",
    )
    parser.add_argument(
        "--alpha",
        type=float,
        default=0.35,
        help="Polygon fill alpha for YOLO-seg labels.",
    )
    parser.add_argument(
        "--ignore-classes",
        default="BACKGROUND,UNLABELLED",
        help=(
            "Comma-separated class names to skip. Defaults to BACKGROUND,UNLABELLED."
        ),
    )
    args = parser.parse_args(argv)

    dataset_root = Path(args.dataset_root).resolve()
    if not dataset_root.is_dir():
        raise FileNotFoundError(f"Dataset root not found: {dataset_root}")
    if args.max_images < 1:
        raise ValueError("--max-images must be greater than zero.")
    if args.line_width < 1:
        raise ValueError("--line-width must be greater than zero.")
    if not 0.0 <= args.alpha <= 1.0:
        raise ValueError("--alpha must be between 0 and 1.")

    output_root = (
        Path(args.output_dir).resolve()
        if args.output_dir
        else dataset_root / "visualizations"
    )
    return VisualizeConfig(
        dataset_root=dataset_root,
        output_root=output_root,
        split=args.split,
        max_images=int(args.max_images),
        line_width=int(args.line_width),
        alpha=float(args.alpha),
        ignore_classes=parse_class_names(args.ignore_classes),
    )


def visualize_dataset(config: VisualizeConfig) -> int:
    """Visualize the requested split(s) and return the number of outputs."""

    classes = read_classes(config.dataset_root / "classes.txt")
    splits = SPLITS if config.split == "all" else (config.split,)
    total = 0
    for split in splits:
        total += visualize_split(config=config, split=split, classes=classes)
    return total


def read_classes(path: Path) -> list[str]:
    """Read class names from classes.txt."""

    if not path.is_file():
        raise FileNotFoundError(f"Missing classes.txt: {path}")
    classes = [line.strip() for line in path.read_text(encoding="utf-8").splitlines()]
    classes = [name for name in classes if name]
    if not classes:
        raise ValueError(f"No class names found in {path}")
    return classes


def parse_class_names(value: str) -> tuple[str, ...]:
    """Parse comma-separated class names."""

    return tuple(name.strip() for name in value.split(",") if name.strip())


def visualize_split(*, config: VisualizeConfig, split: str, classes: list[str]) -> int:
    """Visualize one split and return the number of written images."""

    image_dir = config.dataset_root / "images" / split
    label_dir = config.dataset_root / "labels" / split
    if not image_dir.is_dir():
        print(f"[visualize] skip split={split}: missing {image_dir}")
        return 0
    if not label_dir.is_dir():
        print(f"[visualize] skip split={split}: missing {label_dir}")
        return 0

    output_dir = config.output_root / split
    output_dir.mkdir(parents=True, exist_ok=True)

    image_paths = sorted(
        path
        for path in image_dir.iterdir()
        if path.is_file() and path.suffix.lower() in {".png", ".jpg", ".jpeg"}
    )
    image_paths = image_paths[: config.max_images]

    written = 0
    for image_path in image_paths:
        image = cv2.imread(str(image_path), cv2.IMREAD_COLOR)
        if image is None:
            print(f"[visualize] skip unreadable image: {image_path}")
            continue

        label_path = label_dir / f"{image_path.stem}.txt"
        annotations = read_label_file(label_path)
        rendered = draw_annotations(
            image=image,
            annotations=annotations,
            classes=classes,
            line_width=config.line_width,
            alpha=config.alpha,
            ignore_classes=config.ignore_classes,
        )

        output_path = output_dir / image_path.name
        cv2.imwrite(str(output_path), rendered)
        written += 1
        print(
            f"[visualize] split={split} image={image_path.name} "
            f"labels={len(annotations)} output={output_path}"
        )
    return written


def read_label_file(path: Path) -> list[list[float]]:
    """Read one YOLO label file.

    Missing label files are treated as empty annotations so images without
    objects can still be visualized.
    """

    if not path.is_file():
        return []

    rows: list[list[float]] = []
    for line_number, line in enumerate(
        path.read_text(encoding="utf-8").splitlines(), start=1
    ):
        stripped = line.strip()
        if not stripped:
            continue
        try:
            rows.append([float(token) for token in stripped.split()])
        except ValueError as exc:
            raise ValueError(f"Invalid label row {path}:{line_number}: {line}") from exc
    return rows


def draw_annotations(
    *,
    image: np.ndarray,
    annotations: Iterable[list[float]],
    classes: list[str],
    line_width: int,
    alpha: float,
    ignore_classes: tuple[str, ...],
) -> np.ndarray:
    """Draw bbox or polygon annotations on a BGR image."""

    rendered = image.copy()
    height, width = image.shape[:2]

    for annotation in annotations:
        if len(annotation) < 5:
            continue
        class_id = int(annotation[0])
        class_name = class_label(class_id, classes)
        if should_ignore_class(class_name, ignore_classes):
            continue
        color = class_color(class_id)
        values = annotation[1:]

        if is_bbox(values):
            draw_bbox(
                rendered,
                values=values,
                label=class_name,
                color=color,
                width=width,
                height=height,
                line_width=line_width,
            )
            continue

        if is_polygon(values):
            draw_polygon(
                rendered,
                values=values,
                label=class_name,
                color=color,
                width=width,
                height=height,
                line_width=line_width,
                alpha=alpha,
            )

    return rendered


def is_bbox(values: list[float]) -> bool:
    """Return whether a label payload is a YOLO bbox."""

    return len(values) == 4


def is_polygon(values: list[float]) -> bool:
    """Return whether a label payload is a YOLO-seg polygon."""

    return len(values) >= 6 and len(values) % 2 == 0


def draw_bbox(
    image: np.ndarray,
    *,
    values: list[float],
    label: str,
    color: tuple[int, int, int],
    width: int,
    height: int,
    line_width: int,
) -> None:
    """Draw one YOLO bbox annotation."""

    x1, y1, x2, y2 = bbox_xyxy(values, width=width, height=height)
    cv2.rectangle(image, (x1, y1), (x2, y2), color, thickness=line_width)
    draw_label(image, label, (x1, max(0, y1 - 6)), color)


def draw_polygon(
    image: np.ndarray,
    *,
    values: list[float],
    label: str,
    color: tuple[int, int, int],
    width: int,
    height: int,
    line_width: int,
    alpha: float,
) -> None:
    """Draw one YOLO-seg polygon annotation."""

    polygon = polygon_points(values, width=width, height=height)
    overlay = image.copy()
    cv2.fillPoly(overlay, [polygon], color)
    cv2.addWeighted(overlay, alpha, image, 1.0 - alpha, 0.0, dst=image)
    cv2.polylines(image, [polygon], isClosed=True, color=color, thickness=line_width)
    x, y, _, _ = cv2.boundingRect(polygon)
    draw_label(image, label, (x, max(0, y - 6)), color)


def bbox_xyxy(
    values: list[float], *, width: int, height: int
) -> tuple[int, int, int, int]:
    """Convert normalized YOLO bbox values to pixel xyxy coordinates."""

    cx, cy, box_w, box_h = values
    x1 = int(round((cx - box_w / 2.0) * width))
    y1 = int(round((cy - box_h / 2.0) * height))
    x2 = int(round((cx + box_w / 2.0) * width))
    y2 = int(round((cy + box_h / 2.0) * height))
    return x1, y1, x2, y2


def polygon_points(values: list[float], *, width: int, height: int) -> np.ndarray:
    """Convert normalized YOLO-seg polygon values to pixel points."""

    points = np.asarray(values, dtype=np.float32).reshape(-1, 2)
    points[:, 0] *= width
    points[:, 1] *= height
    return np.round(points).astype(np.int32)


def draw_label(
    image: np.ndarray,
    text: str,
    origin: tuple[int, int],
    color: tuple[int, int, int],
) -> None:
    """Draw a readable label background and text."""

    font = cv2.FONT_HERSHEY_SIMPLEX
    scale = 0.5
    thickness = 1
    (text_width, text_height), baseline = cv2.getTextSize(text, font, scale, thickness)
    x, y = origin
    top_left = (x, max(0, y - text_height - baseline - 4))
    bottom_right = (x + text_width + 6, y + 2)
    cv2.rectangle(image, top_left, bottom_right, color, thickness=-1)
    cv2.putText(
        image,
        text,
        (x + 3, y - 3),
        font,
        scale,
        (255, 255, 255),
        thickness,
        lineType=cv2.LINE_AA,
    )


def class_label(class_id: int, classes: list[str]) -> str:
    """Return a display label for a class id."""

    if 0 <= class_id < len(classes):
        return classes[class_id]
    return str(class_id)


def should_ignore_class(class_name: str, ignore_classes: tuple[str, ...]) -> bool:
    """Return whether a class name should be skipped."""

    return class_name in ignore_classes


_COLOR_CACHE: dict[int, tuple[int, int, int]] = {}


def class_color(class_id: int) -> tuple[int, int, int]:
    """Return a deterministic high-contrast BGR color for a class id."""

    if class_id not in _COLOR_CACHE:
        rng = np.random.default_rng(seed=int(class_id) + 2026)
        color = rng.integers(64, 256, size=3, dtype=np.uint8)
        _COLOR_CACHE[class_id] = int(color[0]), int(color[1]), int(color[2])
    return _COLOR_CACHE[class_id]


if __name__ == "__main__":
    main()
